+<script>
+// =============================================================================
+// NPU Task Manager
+// =============================================================================
+
+class NPUTaskManager {
+    constructor() {
+        this.tasks = [];
+        this.activeTask = null;
+    }
+
+    startTask(task) {
+        this.activeTask = task;
+        this.tasks.push(task);
+        this.updateUI();
+        this.showToast(task);
+    }
+
+    updateTask(progress) {
+        if (!this.activeTask) return;
+
+        this.activeTask.progress = progress.current;
+        this.activeTask.total = progress.total;
+        this.activeTask.eta = progress.eta;
+        this.activeTask.powerWatts = progress.powerWatts;
+
+        this.updateUI();
+    }
+
+    completeTask() {
+        if (!this.activeTask) return;
+
+        this.activeTask.completed = true;
+        this.activeTask = null;
+        this.hideUI();
+        this.showCompletionToast();
+    }
+
+    updateUI() {
+        const npuStatus = document.getElementById('npu-status');
+        const npuProgress = document.getElementById('npu-progress');
+        const npuDetails = document.getElementById('npu-details');
+        const npuProgressFill = document.getElementById('npu-progress-fill');
+        const statusDot = document.getElementById('status-dot');
+
+        if (this.activeTask) {
+            npuStatus.classList.add('active');
+            statusDot.classList.add('npu');
+
+            const { progress, total, name } = this.activeTask;
+            npuProgress.textContent = name;
+            npuDetails.textContent = `${progress}/${total}`;
+
+            const percentage = total > 0 ? (progress / total * 100) : 0;
+            npuProgressFill.style.width = `${percentage}%`;
+        } else {
+            npuStatus.classList.remove('active');
+            statusDot.classList.remove('npu');
+        }
+    }
+
+    hideUI() {
+        document.getElementById('npu-status').classList.remove('active');
+        document.getElementById('status-dot').classList.remove('npu');
+    }
+
+    showToast(task) {
+        const toast = document.getElementById('npu-toast');
+        const title = document.getElementById('npu-toast-title');
+        const body = document.getElementById('npu-toast-body');
+        const eta = document.getElementById('npu-toast-eta');
+        const power = document.getElementById('npu-toast-power');
+
+        title.textContent = task.name;
+        body.textContent = task.description;
+        eta.textContent = task.eta ? `~${task.eta} remaining` : '';
+        power.textContent = task.powerWatts ? `🔋 ${task.powerWatts.toFixed(1)}W` : '';
+
+        toast.classList.add('show');
+
+        // Auto-hide after 5 seconds
+        setTimeout(() => {
+            toast.classList.remove('show');
+        }, 5000);
+    }
+
+    showCompletionToast() {
+        const toast = document.getElementById('npu-toast');
+        const title = document.getElementById('npu-toast-title');
+        const body = document.getElementById('npu-toast-body');
+        const eta = document.getElementById('npu-toast-eta');
+        const power = document.getElementById('npu-toast-power');
+
+        title.textContent = '✅ Indexing Complete';
+        body.textContent = 'Codebase indexed! Semantic search is now available.';
+        eta.textContent = '';
+        power.textContent = '';
+
+        toast.classList.add('show');
+
+        setTimeout(() => {
+            toast.classList.remove('show');
+        }, 3000);
+    }
+}
+
+const npuManager = new NPUTaskManager();
+
+// =============================================================================
+// Swift Bridge API (called from Swift)
+// =============================================================================
+
+window.zellAPI = {
+    // ... existing methods ...
+
+    // NPU task management
+    startNPUTask(task) {
+        npuManager.startTask({
+            name: task.name || 'Background Task',
+            description: task.description || '',
+            progress: 0,
+            total: task.total || 0,
+            eta: task.eta,
+            powerWatts: task.powerWatts || 1.5,
+            completed: false
+        });
+    },
+
+    updateNPUProgress(progress) {
+        npuManager.updateTask({
+            current: progress.current,
+            total: progress.total,
+            eta: progress.eta,
+            powerWatts: progress.powerWatts
+        });
+    },
+
+    completeNPUTask() {
+        npuManager.completeTask();
+    },
+
+    // Example usage from Swift:
+    // startNPUTask({
+    //   name: "Indexing",
+    //   description: "Generating embeddings for 1,247 files...",
+    //   total: 1247,
+    //   eta: "15 min",
+    //   powerWatts: 1.2
+    // })
+};
+
+// =============================================================================
+// Demo: Simulate NPU task (remove in production)
+// =============================================================================
+
+setTimeout(() => {
+    // Auto-start demo NPU task after 3 seconds
+    window.zellAPI.startNPUTask({
+        name: 'Indexing',
+        description: 'Generating embeddings for 1,247 files...',
+        total: 1247,
+        eta: '15 min',
+        powerWatts: 1.2
+    });
+
+    // Simulate progress
+    let current = 0;
+    const interval = setInterval(() => {
+        current += 50;
+
+        if (current >= 1247) {
+            clearInterval(interval);
+            window.zellAPI.completeNPUTask();
+        } else {
+            const remaining = Math.ceil((1247 - current) / 50 * 0.7); // ~0.7 min per 50 files
+            window.zellAPI.updateNPUProgress({
