+//! Benchmark wrapper with proper autoreleasepool management
+//! This wraps each iteration in its own @autoreleasepool to prevent crashes
+
+#import <Foundation/Foundation.h>
+#import <Metal/Metal.h>
+
+// Callback type for benchmark iteration
+typedef void (*BenchmarkIterationCallback)(void* context, int iteration);
+
+// Run benchmark loop with proper autoreleasepool management
+// This prevents Metal object accumulation that causes crashes
+void benchmark_run_with_autorelease(
+    int num_iterations,
+    BenchmarkIterationCallback callback,
+    void* context
+) {
+    for (int i = 0; i < num_iterations; i++) {
+        @autoreleasepool {
+            // Each iteration gets its own pool
+            // This ensures Metal objects are released before next iteration
+            callback(context, i);
+        }
+    }
+}

