+//! vDSP Matrix Multiplication (Accelerate framework)
+//!
+//! Uses Apple's vDSP (Vector Digital Signal Processing) which is highly optimized
+//! and can leverage AMX (Apple Matrix coprocessor) for matrix operations.
+//!
+//! Advantages over CBLAS:
+//! 1. vDSP may use AMX for matrix multiply on M1/M2/M3
+//! 2. Optimized specifically for Apple Silicon
+//! 3. Simple stride-based API
+//!
+//! Note: vDSP works with Float32. We convert BF16→Float32→BF16.
+
+const std = @import("std");
+const BF16 = @import("gguf_loader.zig").BF16;
+
+const log = std.log.scoped(.vdsp_matmul);
+
+// vDSP C API bindings
+pub const c = struct {
+    pub const vDSP_Length = c_ulong;
+    pub const vDSP_Stride = c_long;
+
+    // vDSP_mmul: C[M,N] = A[M,P] × B[P,N]
+    // Strides are in elements (not bytes)
+    // For contiguous arrays, use stride=1
+    extern "c" fn vDSP_mmul(
+        a: [*]const f32,      // Matrix A
+        ia: vDSP_Stride,      // Stride for A
+        b: [*]const f32,      // Matrix B
+        ib: vDSP_Stride,      // Stride for B
+        c: [*]f32,            // Matrix C (output)
+        ic: vDSP_Stride,      // Stride for C
+        m: vDSP_Length,       // Rows of A and C
+        n: vDSP_Length,       // Cols of B and C
+        p: vDSP_Length,       // Cols of A, rows of B
+    ) void;
+};
+
+/// Helper to convert BF16 to Float32
+inline fn bf16ToF32(bf16: BF16) f32 {
+    // BF16 is the upper 16 bits of Float32
+    const u32_val: u32 = @as(u32, bf16) << 16;
+    return @bitCast(u32_val);
+}
+
+/// Helper to convert Float32 to BF16
+inline fn f32ToBF16(f32_val: f32) BF16 {
+    // Take upper 16 bits of Float32
+    const u32_val: u32 = @bitCast(f32_val);
+    return @truncate(u32_val >> 16);
+}
+
+/// vDSP Matmul Engine
+/// Uses vDSP_mmul which can leverage AMX for acceleration
+pub const VdspMatmulEngine = struct {
+    allocator: std.mem.Allocator,
+
+    const Self = @This();
+
+    pub fn init(allocator: std.mem.Allocator) !*Self {
+        const self = try allocator.create(Self);
+        self.* = .{
+            .allocator = allocator,
+        };
+
+        log.info("Initializing vDSP Matmul Engine (AMX acceleration)", .{});
+        log.info("vDSP ready - will use AMX matrix coprocessor for acceleration", .{});
+
+        return self;
+    }
+
+    pub fn deinit(self: *Self) void {
+        self.allocator.destroy(self);
+    }
+
+    /// Matrix multiplication: C = A × B
+    ///
+    /// This uses vDSP_mmul which can leverage AMX (Apple Matrix coprocessor).
+    ///
+    /// A: [M, K]
+    /// B: [K, N]
+    /// C: [M, N]
+    pub fn matmul(
+        self: *Self,
+        a: []const BF16,  // [M, K]
+        b: []const BF16,  // [K, N]
+        c_out: []BF16,    // [M, N] output
+        m: u32,
+        k: u32,
+        n: u32,
+    ) !void {
+        // Allocate Float32 buffers for conversion
+        const a_f32 = try self.allocator.alloc(f32, m * k);
+        defer self.allocator.free(a_f32);
+        const b_f32 = try self.allocator.alloc(f32, k * n);
+        defer self.allocator.free(b_f32);
+        const c_f32 = try self.allocator.alloc(f32, m * n);
+        defer self.allocator.free(c_f32);
+
+        // Convert BF16 to Float32
+        for (a, 0..) |val, i| {
+            a_f32[i] = bf16ToF32(val);
+        }
+        for (b, 0..) |val, i| {
+            b_f32[i] = bf16ToF32(val);
+        }
+
+        // Call vDSP_mmul: C[M,N] = A[M,K] × B[K,N]
+        // Using stride=1 for contiguous arrays
+        c.vDSP_mmul(
+            a_f32.ptr,              // A
+            1,                      // stride for A
+            b_f32.ptr,              // B
+            1,                      // stride for B
+            c_f32.ptr,              // C
+            1,                      // stride for C
+            @intCast(m),            // M
+            @intCast(n),            // N
+            @intCast(k),            // P (K)
+        );
+
+        // Convert Float32 back to BF16
+        for (c_f32, 0..) |val, i| {
+            c_out[i] = f32ToBF16(val);
+        }
+
+        log.debug("vDSP matmul [{}, {}] × [{}, {}] completed (AMX-accelerated)", .{
+            m, k, k, n,
+        });
+    }
+
+    /// QKV projection: [1, hidden] × [hidden, hidden] = [1, hidden]
+    /// Perfect for AMX: M=1, large K/N
+    pub fn qkvProjection(
+        self: *Self,
+        hidden_state: []const BF16,  // [1, hidden_size]
+        weight: []const BF16,         // [hidden_size, hidden_size]
+        output: []BF16,               // [1, hidden_size]
+        hidden_size: u32,
+    ) !void {
+        try self.matmul(
+            hidden_state,
+            weight,
+            output,
