+                    // Exact match - re-process last token to get logits
+                    // Adjust pos back by 1 so we re-process the last cached token
+                    cell.pos = prefix.token_count - 1;
+                    try cell.queueInput(token_slice[prefix.token_count - 1 ..]);
+                }
+
+                cell.max_tokens = max_tokens;
+                cell.state = .thinking;
+
+                // Update cache timestamp
+                try self.prefix_cache.put(prefix_hash, .{
+                    .cell_id = prefix.cell_id,
+                    .token_count = prefix.token_count,
+                    .last_used = std.time.milliTimestamp(),
+                });
+
+                return; // Done - cache hit!
+            }
+        }
+
+        // Cache miss or invalid cache - clear and process normally
+        const memory = c.llama_get_memory(self.ctx);
+        if (memory != null) {
+            _ = c.llama_memory_seq_rm(memory, @intCast(cell_id), -1, -1);
+        }
+
+        // Queue tokens and start
+        cell.reset();
+        try cell.queueInput(token_slice);
+        cell.max_tokens = max_tokens;
+        cell.state = .thinking;
+        logger.debug("Cell {} ready: {} tokens queued, max_tokens={}, state={}", .{ cell_id, cell.input_tokens.items.len, cell.max_tokens, cell.state });
+
+        // Register this prefix in cache for future reuse
+        // Use up to 1024 tokens to support full system prompt caching
+        const prefix_len = @min(token_slice.len, 1024);
+        try self.prefix_cache.put(prefix_hash, .{
+            .cell_id = cell_id,
+            .token_count = @intCast(prefix_len),
+            .last_used = std.time.milliTimestamp(),
+        });
+    }
+
+    /// Find an idle cell, returns null if all cells are busy
+    pub fn findIdleCell(self: *Self) ?u32 {
+        for (self.cells, 0..) |*cell, i| {
+            if (cell.state == .idle) {
+                return @intCast(i);
+            }
+        }
+        return null;
+    }
+
+    /// Clear KV cache for a cell (must be called before cell.reset() to avoid EOG contamination)
+    pub fn clearCellKVCache(self: *Self, cell_id: u32) void {
+        // Clear memory/KV cache for this cell's sequence
+        // This prevents EOG tokens from previous generations from affecting new ones
+        const memory = c.llama_get_memory(self.ctx);
+        if (memory != null) {
+            _ = c.llama_memory_seq_rm(memory, @intCast(cell_id), -1, -1);
+        }
+
+        // Invalidate any prefix cache entries that point to this cell
+        // This is critical because the KV cache now contains generated tokens
+        // which would contaminate future requests using the same prefix
+        var keys_to_remove: std.ArrayListUnmanaged(u64) = .{};
+        defer keys_to_remove.deinit(self.allocator);
+
+        var iter = self.prefix_cache.iterator();
+        while (iter.next()) |entry| {
+            if (entry.value_ptr.cell_id == cell_id) {
+                keys_to_remove.append(self.allocator, entry.key_ptr.*) catch {};
+            }
+        }
+
+        for (keys_to_remove.items) |key| {
+            _ = self.prefix_cache.remove(key);
+        }
+
+        if (keys_to_remove.items.len > 0) {
+            logger.debug("Invalidated {} prefix cache entries for cell {}", .{ keys_to_remove.items.len, cell_id });
+        }
+        logger.debug("Cleared KV cache for cell {}", .{cell_id});
+    }
+
+    /// GATHER phase: Collect pending tokens from active cells into batch
+    /// Returns: (any_active, cell_logits_idx array)
+    fn gatherPhase(self: *Self) !struct { any_active: bool, cell_logits_idx: [32]i32 } {
+        var any_active = false;
+        self.batch.n_tokens = 0;
+        var batch_idx: usize = 0;
+        var cell_logits_idx: [32]i32 = .{-1} ** 32;
+
+        for (self.cells) |*cell| {
+            if (cell.state != .thinking) continue;
+            any_active = true;
+
+            const tokens_to_add = @min(cell.input_tokens.items.len, self.opts.batch_size - batch_idx);
+            if (tokens_to_add == 0) continue;
+
+            const is_speculating = cell.speculated_tokens.items.len > 0;
+            const first_batch_idx = batch_idx;
+
+            for (cell.input_tokens.items[0..tokens_to_add]) |token| {
+                self.batch.token[batch_idx] = token;
+                self.batch.pos[batch_idx] = @intCast(cell.pos);
+                self.batch.n_seq_id[batch_idx] = 1;
+                self.batch.seq_id[batch_idx][0] = @intCast(cell.id);
+                self.batch.logits[batch_idx] = if (is_speculating) 1 else 0;
+                cell.pos += 1;
+                batch_idx += 1;
+            }
+
+            self.batch.logits[batch_idx - 1] = 1;
+            cell_logits_idx[cell.id] = if (is_speculating) @intCast(first_batch_idx) else @intCast(batch_idx - 1);
+
+            if (tokens_to_add == cell.input_tokens.items.len) {
+                cell.input_tokens.clearRetainingCapacity();
+            } else {
+                const remaining = cell.input_tokens.items.len - tokens_to_add;
+                std.mem.copyForwards(
+                    c.llama_token,
+                    cell.input_tokens.items[0..remaining],
+                    cell.input_tokens.items[tokens_to_add..],
+                );
+                cell.input_tokens.items.len = remaining;
+            }
+        }
+
+        self.batch.n_tokens = @intCast(batch_idx);
+        return .{ .any_active = any_active, .cell_logits_idx = cell_logits_idx };
+    }
+
+    /// DISPATCH phase: Sample tokens and handle speculation verification
+    fn dispatchPhase(self: *Self, cell_logits_idx: [32]i32) !void {
+        const vocab = self.model.getVocab();
+
+        for (self.cells, 0..) |*cell, cell_idx| {
+            if (cell.state != .thinking) continue;
+
+            const logits_idx = cell_logits_idx[cell.id];
+            if (logits_idx < 0) continue;
+
+            // Speculation verification mode
+            if (cell.speculated_tokens.items.len > 0) {
+                var accepted: u32 = 0;
+                const spec_tokens = cell.speculated_tokens.items;
+
+                for (spec_tokens, 0..) |expected_token, i| {
+                    const verify_idx = logits_idx + @as(i32, @intCast(i));
+                    const sampled = c.llama_sampler_sample(self.sampler, self.ctx, verify_idx);
+
+                    if (sampled == expected_token) {
+                        accepted += 1;
+                        self.ngram_cache.recordToken(sampled);
+
+                        var token_buf: [128]u8 = undefined;
+                        const token_len = c.llama_token_to_piece(vocab, sampled, &token_buf, @intCast(token_buf.len), 0, true);
+                        if (token_len > 0) {
+                            const token_str = token_buf[0..@intCast(token_len)];
+                            try cell.buffer.appendSlice(cell.allocator, token_str);
+                            if (cell.token_callback) |callback| {
+                                const c_str = cell.allocator.allocSentinel(u8, token_str.len, 0) catch continue;
+                                @memcpy(c_str[0..token_str.len], token_str);
+                                callback(c_str.ptr, @intCast(token_str.len), cell.callback_user_data);
+                                cell.allocator.free(c_str);
+                            }
+                        }
+                        cell.generated_count += 1;
+                    } else {
+                        const rejected = spec_tokens.len - i;
+                        const rollback_from: i32 = @intCast(cell.pos - rejected);
+
+                        const memory = c.llama_get_memory(self.ctx);
+                        if (memory != null) {
+                            _ = c.llama_memory_seq_rm(memory, @intCast(cell.id), rollback_from, -1);
+                        }
+
+                        cell.pos -= @intCast(rejected);
+                        break;
+                    }
+                }
+
+                if (spec_tokens.len > 0) {
+                    var ctx_buf: [4]i32 = undefined;
+                    ctx_buf[0] = @intCast(spec_tokens[0]);
+                    self.ngram_cache.reportResult(&ctx_buf, accepted);
+
+                    if (accepted > 0) {
+                        logger.debug("Cell {} speculation: accepted {}/{} tokens", .{ cell.id, accepted, spec_tokens.len });
+                    }
+                }
+
+                cell.speculated_tokens.clearRetainingCapacity();
+
+                const last_verify_idx = logits_idx + @as(i32, @intCast(accepted));
+                const new_token = c.llama_sampler_sample(self.sampler, self.ctx, last_verify_idx);
+
+                if (c.llama_vocab_is_eog(vocab, new_token)) {
+                    cell.state = .completed;
+                    if (cell.token_callback) |callback| {
+                        callback("", 0, cell.callback_user_data);
+                    }
+                    continue;
+                }
+
+                var token_buf: [128]u8 = undefined;
+                const token_len = c.llama_token_to_piece(vocab, new_token, &token_buf, @intCast(token_buf.len), 0, true);
+                if (token_len > 0) {
+                    const token_str = token_buf[0..@intCast(token_len)];
+                    try cell.buffer.appendSlice(cell.allocator, token_str);
+                    if (cell.token_callback) |callback| {
+                        const c_str = cell.allocator.allocSentinel(u8, token_str.len, 0) catch continue;
+                        @memcpy(c_str[0..token_str.len], token_str);
+                        callback(c_str.ptr, @intCast(token_str.len), cell.callback_user_data);
+                        cell.allocator.free(c_str);
+                    }
+                }
+
+                self.ngram_cache.recordToken(new_token);
+                cell.generated_count += 1;
+                try cell.queueInput(&[_]c.llama_token{new_token});
+                continue;
+            }
+
+            // Normal single-token sampling
+            const new_token = c.llama_sampler_sample(self.sampler, self.ctx, logits_idx);
+
+            if (c.llama_vocab_is_eog(vocab, new_token)) {
+                cell.state = .completed;
+                if (cell.token_callback) |callback| {
+                    callback("", 0, cell.callback_user_data);
+                }
+                continue;
+            }
+
+            cell.generated_count += 1;
+            if (cell.generated_count >= cell.max_tokens) {
+                cell.state = .completed;
+                if (cell.token_callback) |callback| {
+                    callback("", 0, cell.callback_user_data);
+                }
+                continue;
+            }
+
+            if (cell.pos >= self.opts.context_per_cell) {
+                cell.state = .completed;
+                if (cell.token_callback) |callback| {
+                    callback("", 0, cell.callback_user_data);
+                }
+                continue;
+            }
+
+            var token_buf: [128]u8 = undefined;
+            const token_len = c.llama_token_to_piece(vocab, new_token, &token_buf, @intCast(token_buf.len), 0, true);
+
+            if (token_len > 0) {
+                const token_str = token_buf[0..@intCast(token_len)];
+                try cell.buffer.appendSlice(cell.allocator, token_str);
+
+                if (cell.token_callback) |callback| {
+                    const new_bytes = cell.buffer.items[cell.bytes_consumed..];
+                    if (new_bytes.len > 0) {
+                        const c_str = cell.allocator.allocSentinel(u8, new_bytes.len, 0) catch continue;
+                        @memcpy(c_str[0..new_bytes.len], new_bytes);
+                        callback(c_str.ptr, @intCast(new_bytes.len), cell.callback_user_data);
+                        cell.allocator.free(c_str);
+                        cell.bytes_consumed = cell.buffer.items.len;
+                    }
+                }
+
+                if (self.opts.enable_tools) {
+                    const maybe_trigger = self.trigger_detectors[cell_idx].feed(token_str) catch |err| blk: {
+                        std.log.err("Cell {}: Trigger detection failed: {}", .{ cell_idx, err });
+                        break :blk null;
+                    };
+                    if (maybe_trigger) |trigger| {
+                        defer self.allocator.free(trigger.content);
+                        try self.handleToolTrigger(cell, @intCast(cell_idx), trigger);
+                        continue;
+                    }
+                }
+            }
+
+            self.ngram_cache.recordToken(new_token);
+            cell.recordRecentToken(new_token);
+            try cell.queueInput(&[_]c.llama_token{new_token});
+
+            // Try speculation
+            if (cell.speculated_tokens.items.len == 0) {
+                const prefix_len = self.ngram_cache.config.prefix_len;
+                if (cell.recent_tokens_count >= prefix_len) {
+                    const context = cell.getRecentTokens(prefix_len);
+
+                    if (self.ngram_cache.speculate(context)) |speculation| {
+                        const spec_count = @min(speculation.len, 4);
+                        if (spec_count > 0) {
+                            cell.speculation_start_pos = cell.pos;
+                            try cell.speculated_tokens.appendSlice(cell.allocator, speculation[0..spec_count]);
+
+                            for (speculation[0..spec_count]) |spec_token| {
+                                try cell.queueInput(&[_]c.llama_token{@intCast(spec_token)});
+                            }
+
+                            logger.info("Cell {} speculating {} tokens from cache", .{ cell.id, spec_count });
+                        }
+                    }
+                }
+            }
+        }
+    }
+
+    /// Run one iteration of the scheduler loop with async pipelining
+    /// (Gather/Crunch/Dispatch) where Crunch runs on worker thread
+    /// Returns true if any cells are still active
+    pub fn step(self: *Self) !bool {
+        const now = std.time.milliTimestamp();
+
+        // Check if there are any pending requests
+        const has_pending = self.hasPendingRequests();
+
+        // Count active cells for debugging
+        var active_count: u32 = 0;
+        for (self.cells) |cell| {
+            if (cell.state == .thinking) active_count += 1;
+        }
+        if (active_count > 0) {
+            logger.debug("Scheduler.step: {} cells in thinking state", .{active_count});
+        }
+
+        if (has_pending) {
+            // Update activity timestamp
+            self.last_activity = now;
+
+            // Wake up hippocampus if it's dreaming or sleeping
+            if (self.hippocampus) |h| {
+                if (h.isDreaming() or h.isDeepSleeping()) {
+                    try h.interrupt();
+                }
+            }
+        } else {
+            // Check for idle threshold to trigger sleep
+            if (now - self.last_activity > self.sleep_threshold_ms) {
+                if (self.hippocampus) |h| {
+                    if (h.isAwake()) {
+                        try h.trySleep();
+                    }
+                }
+            }
+        }
+
+        // Check for groggy timeout (prevents stuck UI)
+        if (self.hippocampus) |h| {
+            h.checkGroggyTimeout();
+        }
+
+        // === ASYNC PIPELINE ===
+        // Step 1: Try to dispatch previous results (non-blocking)
+        if (self.pipeline.result_ready.load(.acquire)) {
+            self.pipeline.mutex.lock();
+            const result = self.pipeline.result;
+            const cell_logits_idx = self.pipeline.request.cell_logits_idx;
+            self.pipeline.result_ready.store(false, .release);
+            self.pipeline.mutex.unlock();
+
+            if (!result.success) {
+                logger.err("Async decode failed: {s}", .{result.error_msg});
+                return error.DecodeFailed;
+            }
+
+            // Dispatch the results
+            try self.dispatchPhase(cell_logits_idx);
+        }
+
+        // Step 2: Gather next batch
+        const gather_result = try self.gatherPhase();
+        const any_active = gather_result.any_active;
+        const cell_logits_idx = gather_result.cell_logits_idx;
+
+        if (self.batch.n_tokens == 0) {
+            logger.debug("Scheduler.step: no tokens in batch, returning any_active={}", .{any_active});
+            // Check if context needs resizing
+            if (try self.shouldResize()) {
+                self.resizeContext() catch |err| {
+                    std.debug.print("⚠ Resize failed: {}, continuing\n", .{err});
+                };
+            }
+            return any_active;
+        }
+
+        logger.debug("Scheduler.step: processing batch with {} tokens", .{self.batch.n_tokens});
+
+        // Step 3: Queue batch for async decode (non-blocking)
+        // Wait if previous decode still running
+        while (self.pipeline.decode_ready.load(.acquire)) {
+            std.time.sleep(10_000); // 0.01ms
+        }
+
+        self.pipeline.mutex.lock();
+        self.pipeline.request = DecodeRequest{
+            .batch = self.batch,
+            .cell_logits_idx = cell_logits_idx,
+            .n_tokens = self.batch.n_tokens,
+        };
+        self.pipeline.decode_ready.store(true, .release);
+        self.pipeline.mutex.unlock();
+
+        // Check if context needs resizing
+
+            // Check if we're verifying speculation
+            if (cell.speculated_tokens.items.len > 0) {
+                // Speculation verification mode
+                var accepted: u32 = 0;
+                const spec_tokens = cell.speculated_tokens.items;
+
+                // Verify each speculated token
+                for (spec_tokens, 0..) |expected_token, i| {
+                    const verify_idx = logits_idx + @as(i32, @intCast(i));
+                    const sampled = c.llama_sampler_sample(self.sampler, self.ctx, verify_idx);
+
+                    if (sampled == expected_token) {
+                        accepted += 1;
+                        // Token matches - record it
+                        self.ngram_cache.recordToken(sampled);
+
+                        // Output the token
+                        var token_buf: [128]u8 = undefined;
+                        const token_len = c.llama_token_to_piece(vocab, sampled, &token_buf, @intCast(token_buf.len), 0, true);
+                        if (token_len > 0) {
+                            const token_str = token_buf[0..@intCast(token_len)];
+                            try cell.buffer.appendSlice(cell.allocator, token_str);
+                            if (cell.token_callback) |callback| {
+                                const c_str = cell.allocator.allocSentinel(u8, token_str.len, 0) catch continue;
+                                @memcpy(c_str[0..token_str.len], token_str);
+                                callback(c_str.ptr, @intCast(token_str.len), cell.callback_user_data);
+                                cell.allocator.free(c_str);
+                            }
+                        }
+                        cell.generated_count += 1;
+                    } else {
+                        // Mismatch - reject remaining speculation
+                        // Roll back position for rejected tokens AND KV cache
+                        const rejected = spec_tokens.len - i;
+                        const rollback_from: i32 = @intCast(cell.pos - rejected);
+
+                        // Remove rejected tokens from KV cache
+                        const memory = c.llama_get_memory(self.ctx);
+                        if (memory != null) {
+                            _ = c.llama_memory_seq_rm(memory, @intCast(cell.id), rollback_from, -1);
+                        }
+
+                        cell.pos -= @intCast(rejected);
+                        break;
+                    }
+                }
+
+                // Report speculation result
+                if (spec_tokens.len > 0) {
+                    // Build context for reporting (simplified)
+                    var ctx_buf: [4]i32 = undefined;
+                    ctx_buf[0] = @intCast(spec_tokens[0]);
+                    self.ngram_cache.reportResult(&ctx_buf, accepted);
+
+                    if (accepted > 0) {
+                        logger.debug("Cell {} speculation: accepted {}/{} tokens", .{ cell.id, accepted, spec_tokens.len });
+                    }
+                }
+
+                // Clear speculation state
+                cell.speculated_tokens.clearRetainingCapacity();
+
+                // Continue to sample next token after speculation
+                const last_verify_idx = logits_idx + @as(i32, @intCast(accepted));
+                const new_token = c.llama_sampler_sample(self.sampler, self.ctx, last_verify_idx);
+
+                if (c.llama_vocab_is_eog(vocab, new_token)) {
+                    cell.state = .completed;
+                    if (cell.token_callback) |callback| {
+                        callback("", 0, cell.callback_user_data);
+                    }
+                    continue;
+                }
+
+                // Output the new token and queue it
+                var token_buf: [128]u8 = undefined;
+                const token_len = c.llama_token_to_piece(vocab, new_token, &token_buf, @intCast(token_buf.len), 0, true);
+                if (token_len > 0) {
+                    const token_str = token_buf[0..@intCast(token_len)];
+                    try cell.buffer.appendSlice(cell.allocator, token_str);
+                    if (cell.token_callback) |callback| {
+                        const c_str = cell.allocator.allocSentinel(u8, token_str.len, 0) catch continue;
+                        @memcpy(c_str[0..token_str.len], token_str);
+                        callback(c_str.ptr, @intCast(token_str.len), cell.callback_user_data);
+                        cell.allocator.free(c_str);
+                    }
+                }
+
+                self.ngram_cache.recordToken(new_token);
+                cell.generated_count += 1;
+                try cell.queueInput(&[_]c.llama_token{new_token});
+                continue;
+            }
+
+            // Normal single-token sampling (no speculation)
+            const new_token = c.llama_sampler_sample(self.sampler, self.ctx, logits_idx);
+
+            // Check for end of generation
+            if (c.llama_vocab_is_eog(vocab, new_token)) {
+                cell.state = .completed;
+                // Send completion signal to Swift callback (empty token)
+                if (cell.token_callback) |callback| {
+                    callback("", 0, cell.callback_user_data);
+                }
+                continue;
+            }
+
+            // Check token limit
+            cell.generated_count += 1;
+            if (cell.generated_count >= cell.max_tokens) {
+                cell.state = .completed;
+                // Send completion signal to Swift callback (empty token)
+                if (cell.token_callback) |callback| {
+                    callback("", 0, cell.callback_user_data);
+                }
+                continue;
+            }
+
+            // Check context limit for this cell
+            if (cell.pos >= self.opts.context_per_cell) {
+                cell.state = .completed;
+                // Send completion signal to Swift callback (empty token)
+                if (cell.token_callback) |callback| {
+                    callback("", 0, cell.callback_user_data);
+                }
+                continue;
+            }
+
+            // Convert token to string and append to buffer
+            var token_buf: [128]u8 = undefined;
+            const token_len = c.llama_token_to_piece(
+                vocab,
+                new_token,
+                &token_buf,
+                @intCast(token_buf.len),
+                0,
+                true,
+            );
+
+            if (token_len > 0) {
+                const token_str = token_buf[0..@intCast(token_len)];
+                try cell.buffer.appendSlice(cell.allocator, token_str);
+
+                // Streaming callback support (for direct Swift integration)
+                if (cell.token_callback) |callback| {
+                    const new_bytes = cell.buffer.items[cell.bytes_consumed..];
+                    if (new_bytes.len > 0) {
+                        // Allocate null-terminated C string for callback
+                        const c_str = cell.allocator.allocSentinel(u8, new_bytes.len, 0) catch continue;
+                        @memcpy(c_str[0..new_bytes.len], new_bytes);
+
+                        // Call Swift callback (from Zig thread)
+                        callback(c_str.ptr, @intCast(new_bytes.len), cell.callback_user_data);
+
+                        // Free C string (Swift has copied it)
+                        cell.allocator.free(c_str);
+
+                        // Update consumed position
+                        cell.bytes_consumed = cell.buffer.items.len;
+                    }
+                }
+
+                // Tool trigger detection
+                if (self.opts.enable_tools) {
+                    const maybe_trigger = self.trigger_detectors[cell_idx].feed(token_str) catch |err| blk: {
+                        std.log.err("Cell {}: Trigger detection failed: {}", .{ cell_idx, err });
+                        break :blk null;
+                    };
+                    if (maybe_trigger) |trigger| {
+                        defer self.allocator.free(trigger.content);
+                        try self.handleToolTrigger(cell, @intCast(cell_idx), trigger);
+                        continue; // Cell is now paused or resumed
+                    }
+                }
+            }
+
+            // Record token in ngram cache and cell's recent history
+            self.ngram_cache.recordToken(new_token);
+            cell.recordRecentToken(new_token);
+
+            // Queue the new token for next iteration
+            try cell.queueInput(&[_]c.llama_token{new_token});
+
+            // Try speculation: check if we have cached continuations
+            // Use cell's recent token history for proper prefix matching
+            if (cell.speculated_tokens.items.len == 0) {
+                const prefix_len = self.ngram_cache.config.prefix_len;
+                if (cell.recent_tokens_count >= prefix_len) {
+                    // Get the last prefix_len tokens for lookup
+                    const context = cell.getRecentTokens(prefix_len);
+
+                    if (self.ngram_cache.speculate(context)) |speculation| {
+                        // Found speculation! Queue all speculated tokens
+                        const spec_count = @min(speculation.len, 4); // Limit speculation depth
+                        if (spec_count > 0) {
+                            cell.speculation_start_pos = cell.pos;
+                            try cell.speculated_tokens.appendSlice(cell.allocator, speculation[0..spec_count]);
+
+                            // Queue speculated tokens for batch verification
+                            for (speculation[0..spec_count]) |spec_token| {
+                                try cell.queueInput(&[_]c.llama_token{@intCast(spec_token)});
+                            }
+
+                            logger.info("Cell {} speculating {} tokens from cache", .{ cell.id, spec_count });
+                        }
+                    }
+                }
+            }
+        }
+
+        // Check if context needs resizing
+        if (try self.shouldResize()) {
+            self.resizeContext() catch |err| {
+                std.debug.print("⚠ Resize failed: {}, continuing\n", .{err});
+            };
+        }
+
+        return any_active;
+    }
+
+    /// Check if context should be resized based on usage and memory pressure
+    fn shouldResize(self: *Self) !bool {
+        if (!self.opts.adaptive_mode) return false;
+        if (self.memory_monitor == null) return false;
+
+        // Check resize interval
+        const now = std.time.milliTimestamp();
+        if ((now - self.last_resize_check) < self.min_resize_interval_ms) {
+            return false;
+        }
+        self.last_resize_check = now;
+
+        // Find max position across all cells
+        var max_pos: u32 = 0;
+        var active_cells: usize = 0;
+        for (self.cells) |cell| {
+            if (cell.state != .idle) {
+                active_cells += 1;
+                if (cell.pos > max_pos) {
+                    max_pos = cell.pos;
+                }
+            }
+        }
+
+        // No active cells - no resize needed
+        if (active_cells == 0) return false;
+
+        // Check token usage vs context per cell
+        const per_cell = self.total_ctx / self.opts.max_cells;
+        const usage_pct = @as(f32, @floatFromInt(max_pos)) /
+                          @as(f32, @floatFromInt(per_cell));
+
+        // Check memory pressure
+        const pressure = try self.memory_monitor.?.getCurrentPressure();
+
+        // Resize if:
+        // 1. Usage exceeds threshold AND memory pressure is low/medium (grow)
+        // 2. OR usage is very low AND memory pressure is high (shrink to free memory)
+        const should_grow = usage_pct >= self.resize_threshold and
+                            (pressure == .low or pressure == .medium);
+
+        // Only shrink if we're using less than 10% of context AND pressure is high
+        // This prevents constant shrink attempts when already at minimum
+        const current_per_cell = self.total_ctx / self.opts.max_cells;
+        const can_shrink = current_per_cell > 512; // Don't shrink below 512 tokens
+        const should_shrink = can_shrink and usage_pct < 0.1 and
+                              (pressure == .high or pressure == .critical);
+
+        if (should_grow or should_shrink) {
+            logger.debug("Resize trigger: usage={d:.1}%, pressure={s}", .{ usage_pct * 100.0, pressure.toString() });
+            return true;
+        }
+
+        return false;
+    }
+
+    /// Resize context to accommodate growing workload
+    fn resizeContext(self: *Self) !void {
+        if (!self.opts.adaptive_mode) return;
+        if (self.memory_monitor == null) return;
+
+        // Check if any cells are waiting for tools (unsafe to resize)
+        for (self.cells) |cell| {
+            if (cell.state == .waiting_for_tool) {
+                std.debug.print("⏸ Deferring resize: cells waiting for tools\n", .{});
+                return;
+            }
+        }
+
+        // Calculate new context size (grow by 2x, respecting per-cell budget)
+        const current_per_cell = self.total_ctx / self.opts.max_cells;
+        const new_per_cell = @min(current_per_cell * 2, 4096);
+        const new_total_ctx = new_per_cell * self.opts.max_cells;
+
+        if (new_total_ctx == self.total_ctx) {
+            logger.debug("Already at maximum context size", .{});
+            return;
+        }
+
+        logger.info("Resizing context: {} -> {} tokens ({} per cell)", .{ self.total_ctx, new_total_ctx, new_per_cell });
+
+        // 1. Save all active cell states using existing API
+        var cell_states: std.ArrayListUnmanaged([]u8) = .empty;
+        defer {
+            for (cell_states.items) |state| {
+                self.allocator.free(state);
+            }
+            cell_states.deinit(self.allocator);
+        }
+        try cell_states.ensureTotalCapacity(self.allocator, self.cells.len);
+
+        for (self.cells) |cell| {
+            if (cell.state == .idle) {
+                try cell_states.append(self.allocator, &[_]u8{});
+                continue;
+            }
+
+            // Use llama_state_seq_get_size and llama_state_seq_get_data
+            const size = c.llama_state_seq_get_size(self.ctx, @intCast(cell.id));
+            const state = try self.allocator.alloc(u8, size);
+            errdefer self.allocator.free(state);
+
+            const written = c.llama_state_seq_get_data(
+                self.ctx,
+                state.ptr,
+                size,
+                @intCast(cell.id),
+            );
+
+            if (written != size) {
+                return error.StateSaveFailed;
+            }
+
+            try cell_states.append(self.allocator, state);
+        }
+
+        // 2. Create new context with larger size
+        var new_ctx_params = c.llama_context_default_params();
+        new_ctx_params.n_ctx = new_total_ctx;
+        new_ctx_params.n_batch = self.opts.batch_size;
+        new_ctx_params.n_threads = @intCast(std.Thread.getCpuCount() catch 4);
+        new_ctx_params.n_threads_batch = new_ctx_params.n_threads;
+        // CRITICAL: Enable continuous batching with multiple sequences
+        new_ctx_params.n_seq_max = @intCast(self.opts.max_cells);
+
+        const new_ctx = c.llama_init_from_model(self.model.handle, new_ctx_params) orelse {
+            return error.ContextInitFailed;
+        };
+        errdefer c.llama_free(new_ctx);
+
+        // 3. Restore all cell states to new context
+        for (self.cells, 0..) |cell, i| {
+            if (cell.state == .idle) continue;
+
+            const state = cell_states.items[i];
+            if (state.len == 0) continue;
+
+            const read = c.llama_state_seq_set_data(
+                new_ctx,
+                state.ptr,
+                state.len,
+                @intCast(cell.id),
+            );
+
+            if (read != state.len) {
+                return error.StateRestoreFailed;
+            }
+        }
+
+        // 4. Recreate sampler for new context
+        const new_sampler = c.llama_sampler_chain_init(c.llama_sampler_chain_default_params()) orelse {
+            return error.SamplerInitFailed;
+        };
+        c.llama_sampler_chain_add(new_sampler, c.llama_sampler_init_temp(0.7));
+        c.llama_sampler_chain_add(new_sampler, c.llama_sampler_init_dist(0));
+
+        // 5. Swap contexts
+        const old_ctx = self.ctx;
+        const old_sampler = self.sampler;
+
+        self.ctx = new_ctx;
+        self.sampler = new_sampler;
+        self.total_ctx = new_total_ctx;
+
+        // 6. Cleanup old context
+        c.llama_sampler_free(old_sampler);
+        c.llama_free(old_ctx);
+
+        logger.info("Resize complete: {} tokens total ({} per cell)",
+            .{new_total_ctx, new_per_cell});
+    }
+
+    /// Handle a detected tool trigger - execute tool and inject result
+    fn handleToolTrigger(self: *Self, cell: *Cell, cell_id: u32, trigger: triggers.DetectedTrigger) !void {
+        // Pause the cell for tool execution
+        cell.state = .waiting_for_tool;
+
+        // Create tool request
+        const request = tools.ToolRequest{
+            .tool = trigger.tool,
+            .cell_id = cell_id,
+            .payload = trigger.content,
+        };
+
+        // Execute tool (blocking)
+        const result = self.tool_registry.execute(request);
+
+        // Format result for injection into context
+        var result_text: std.ArrayListUnmanaged(u8) = .empty;
+        defer result_text.deinit(self.allocator);
+
+        if (result.success) {
+            try result_text.appendSlice(self.allocator, "\n<RESULT>\n");
+            try result_text.appendSlice(self.allocator, result.output);
+            try result_text.appendSlice(self.allocator, "\n</RESULT>\n");
+        } else {
+            try result_text.appendSlice(self.allocator, "\n<ERROR>");
+            try result_text.appendSlice(self.allocator, result.error_msg orelse "Unknown error");
+            try result_text.appendSlice(self.allocator, "</ERROR>\n");
+        }
+
+        // Resume cell with result
+        try self.resumeCell(cell_id, result_text.items);
+
+        // Reset trigger detector for this cell
+        self.trigger_detectors[cell_id].reset();
+    }
+
+    /// Run until all cells complete or reach max iterations
+    pub fn runUntilComplete(self: *Self, max_iterations: u32) !void {
+        var iterations: u32 = 0;
+        while (iterations < max_iterations) : (iterations += 1) {
+            const active = try self.step();
+            if (!active) break;
+        }
+    }
+
+    /// Get a cell by ID
+    pub fn getCell(self: *Self, cell_id: u32) ?*Cell {
+        if (cell_id >= self.cells.len) return null;
+        return &self.cells[cell_id];
+    }
+
+    /// Get the tool registry for configuration
+    pub fn getToolRegistry(self: *Self) *tools.ToolRegistry {
+        return &self.tool_registry;
+    }
+
+    /// Pause a cell (for tool execution)
+    pub fn pauseCell(self: *Self, cell_id: u32) !void {
+        if (cell_id >= self.cells.len) return error.InvalidCellId;
+        var cell = &self.cells[cell_id];
+        if (cell.state == .thinking) {
+            cell.state = .waiting_for_tool;
+        }
+    }
+
+    /// Resume a cell with tool result injected into context
+    pub fn resumeCell(self: *Self, cell_id: u32, tool_result: []const u8) !void {
+        if (cell_id >= self.cells.len) return error.InvalidCellId;
+        var cell = &self.cells[cell_id];
+        if (cell.state != .waiting_for_tool) return error.CellNotWaiting;
+
+        // Tokenize tool result
+        const vocab = self.model.getVocab();
+        var tokens: [4096]c.llama_token = undefined;
+        const n_tokens = c.llama_tokenize(
+            vocab,
+            tool_result.ptr,
+            @intCast(tool_result.len),
+            &tokens,
+            @intCast(tokens.len),
+            false, // don't add special tokens
+            true,
+        );
+
+        if (n_tokens < 0) {
+            return error.TokenizationFailed;
+        }
+
+        // Queue tool result tokens and resume
+        try cell.queueInput(tokens[0..@intCast(n_tokens)]);
+        cell.state = .thinking;
+    }
