+    /// Cell snapshot header for per-cell state files
+    pub const CellSnapshotHeader = extern struct {
+        magic: u32 = 0x43454C4C, // 'CELL'
+        version: u32 = 1,
+        seq_id: u32,
+        pos: u32,
+        state_size: u64,
+        _pad: [8]u8 = [_]u8{0} ** 8,
+    };
+
+    /// Save a single cell's KV cache state to file
+    pub fn saveCellSnapshot(self: *Self, cell_id: u32, path: []const u8) !void {
+        if (cell_id >= self.cells.len) return error.InvalidCellId;
+
+        const cell = &self.cells[cell_id];
+
+        // Get sequence state size
+        const size = c.llama_state_seq_get_size(self.ctx, @intCast(cell_id));
+        if (size == 0) return error.EmptyState;
+
+        const buffer = try self.allocator.alloc(u8, size);
+        defer self.allocator.free(buffer);
+
+        // Serialize sequence state
+        const written = c.llama_state_seq_get_data(self.ctx, buffer.ptr, size, @intCast(cell_id));
+        if (written == 0) return error.StateSaveFailed;
+
+        // Write to file with header
+        const file = try std.fs.cwd().createFile(path, .{});
+        defer file.close();
+
+        const header = CellSnapshotHeader{
+            .seq_id = cell_id,
+            .pos = cell.pos,
+            .state_size = written,
+        };
+        try file.writeAll(std.mem.asBytes(&header));
+        try file.writeAll(buffer[0..written]);
+    }
+
+    /// Load a cell snapshot into a specific cell
+    pub fn loadCellSnapshot(self: *Self, cell_id: u32, path: []const u8) !void {
+        if (cell_id >= self.cells.len) return error.InvalidCellId;
+
+        const file = try std.fs.cwd().openFile(path, .{});
+        defer file.close();
+
+        // Read header
+        var header: CellSnapshotHeader = undefined;
+        _ = try file.readAll(std.mem.asBytes(&header));
+
+        if (header.magic != 0x43454C4C) return error.InvalidSnapshotMagic;
+        if (header.version != 1) return error.UnsupportedSnapshotVersion;
+
+        // Read state
+        const buffer = try self.allocator.alloc(u8, header.state_size);
+        defer self.allocator.free(buffer);
+        _ = try file.readAll(buffer);
+
+        // Clear existing cell state
+        const memory = c.llama_get_memory(self.ctx);
+        if (memory != null) {
+            _ = c.llama_memory_seq_rm(memory, @intCast(cell_id), -1, -1);
+        }
+
+        // Restore state to specified cell
+        const read = c.llama_state_seq_set_data(self.ctx, buffer.ptr, buffer.len, @intCast(cell_id));
+        if (read == 0) return error.StateLoadFailed;
+
+        // Update cell metadata
+        var cell = &self.cells[cell_id];
+        cell.pos = header.pos;
+        cell.state = .idle;
+    }
+
+    /// Clone a cell's state to another cell (for forking inference)
+    pub fn cloneCellState(self: *Self, src_cell_id: u32, dst_cell_id: u32) !void {
+        if (src_cell_id >= self.cells.len) return error.InvalidCellId;
+        if (dst_cell_id >= self.cells.len) return error.InvalidCellId;
+
+        // Get source state
+        const size = c.llama_state_seq_get_size(self.ctx, @intCast(src_cell_id));
+        if (size == 0) return error.EmptyState;
+
+        const buffer = try self.allocator.alloc(u8, size);
+        defer self.allocator.free(buffer);
+
+        const written = c.llama_state_seq_get_data(self.ctx, buffer.ptr, size, @intCast(src_cell_id));
+        if (written == 0) return error.StateSaveFailed;
+
+        // Clear destination cell
+        const memory = c.llama_get_memory(self.ctx);
+        if (memory != null) {
+            _ = c.llama_memory_seq_rm(memory, @intCast(dst_cell_id), -1, -1);
+        }
+
+        // Restore to destination
+        const read = c.llama_state_seq_set_data(self.ctx, buffer.ptr, written, @intCast(dst_cell_id));
+        if (read == 0) return error.StateLoadFailed;
+
+        // Copy cell metadata
+        const src_cell = &self.cells[src_cell_id];
+        var dst_cell = &self.cells[dst_cell_id];
+        dst_cell.pos = src_cell.pos;
+        dst_cell.state = .idle;
+    }
+
+    /// Share KV cache prefix from one cell to all other idle cells (zero-copy)
+    /// This enables parallel cells to reuse the same computed prefix (e.g., system prompt)
+    /// without reprocessing it in each cell.
+    ///
+    /// Usage: After cell 0 processes a system prompt, call this to share it with cells 1-7
+    ///
+    /// prefix_length: Number of tokens in the prefix to share (-1 = all processed tokens)
+    pub fn sharePrefixAcrossCells(
+        self: *Self,
+        source_cell_id: u32,
+        prefix_length: i32,
+    ) !void {
+        if (source_cell_id >= self.cells.len) {
+            return error.InvalidCellId;
+        }
+
+        const source_cell = &self.cells[source_cell_id];
+        if (source_cell.state == .idle) {
+            return error.SourceCellNotActive;
+        }
+
+        // Wrap context for llama.zig API
+        const ctx_wrapper = llama.Context{
+            .handle = self.ctx,
+            .model = self.model,
+            .sampler = self.sampler,
+        };
+
+        // Copy KV cache from source to all idle cells
+        for (self.cells, 0..) |*cell, i| {
+            if (i == source_cell_id) continue; // Skip source
+            if (cell.state != .idle) continue; // Only copy to idle cells
+
+            const src_seq_id = @as(i32, @intCast(source_cell_id));
+            const dest_seq_id = @as(i32, @intCast(i));
+
+            // Zero-copy KV cache sharing via llama.cpp
+            llama.memoryCopySeq(&ctx_wrapper, src_seq_id, dest_seq_id, 0, prefix_length);
+
+            // Update destination cell position to reflect shared prefix
+            cell.pos = @intCast(if (prefix_length < 0) source_cell.pos else @as(u32, @intCast(prefix_length)));
+        }
+    }
+};
