+const std = @import("std");
+
+// BNNS C API
+const c = struct {
+    pub const BNNSDataTypeFloat32: c_int = 0x10020; // 0x10000 | 32
+
+    pub const BNNSNDArrayDescriptor = extern struct {
+        flags: u32,
+        layout: c_int,
+        size: [8]usize,
+        stride: [8]usize,
+        data: ?*anyopaque,
+        data_type: c_int,
+        table_data: ?*anyopaque,
+        table_data_type: c_int,
+        data_scale: f32,
+        data_bias: f32,
+    };
+
+    extern "c" fn BNNSDirectApplyBroadcastMatMul(
+        transA: bool,
+        transB: bool,
+        alpha: f32,
+        inputA: *const BNNSNDArrayDescriptor,
+        inputB: *const BNNSNDArrayDescriptor,
+        output: *const BNNSNDArrayDescriptor,
+        filter_params: ?*const anyopaque,
+    ) void;
+};
+
+fn createMatrixDesc(
+    data: *anyopaque,
+    rows: usize,
+    cols: usize,
+) c.BNNSNDArrayDescriptor {
+    // For BroadcastMatMul, perhaps we need batch dimension
+    // Try: [batch=1, rows, cols] with appropriate strides
+    // stride[0] = rows * cols (batch stride)
+    // stride[1] = cols (row stride)
+    // stride[2] = 1 (column stride)
+    return c.BNNSNDArrayDescriptor{
+        .flags = 0,
+        .layout = 0, // Try layout 0 instead
+        .size = .{ 1, rows, cols, 1, 1, 1, 1, 1 },
+        .stride = .{ rows * cols, cols, 1, 0, 0, 0, 0, 0 },
+        .data = data,
+        .data_type = c.BNNSDataTypeFloat32,
+        .table_data = null,
+        .table_data_type = 0,
+        .data_scale = 1.0,
+        .data_bias = 0.0,
+    };
+}
