+    std.debug.print("║  Heterogeneous Parallel Computing Test                   ║\n", .{});
+    std.debug.print("║  GPU (Metal BF16) + NPU (BNNS/ANE) Concurrency          ║\n", .{});
+    std.debug.print("╚═══════════════════════════════════════════════════════════╝\n\n", .{});
