+    std.debug.print("   GPU: Metal BF16 (high performance)\n", .{});
+    std.debug.print("   NPU: BNNS ANE (low power)\n\n", .{});
+
+    // ═══════════════════════════════════════════════════════════════
+    // Test 1: GPU-Only Baseline (Sequential)
+    // ═══════════════════════════════════════════════════════════════
+    std.debug.print("═══════════════════════════════════════════════════════════\n", .{});
+    std.debug.print("Test 1: GPU-Only Baseline (Sequential Large Matmuls)\n", .{});
+    std.debug.print("═══════════════════════════════════════════════════════════\n\n", .{});
+
+    // Large matmul (main LLM workload)
