+//! Threaded Heterogeneous Parallel Test: GPU + NPU
+//!
+//! This test uses std.Thread to launch GPU and NPU work truly in parallel.
+//! Previous test showed promising results - now let's verify with real threading.
+
+const std = @import("std");
+const BF16 = @import("inference/gguf_loader.zig").BF16;
+const metal_bf16 = @import("inference/metal_bf16_matmul.zig");
+const bnns_ane = @import("inference/bnns_ane_matmul.zig");
+const objc = @import("inference/metal/objc.zig");
+
+const NPUTask = struct {
+    engine: *bnns_ane.BNNSANEMatmulEngine,
+    a: []const BF16,
+    b: []const BF16,
+    c: []BF16,
+    m: u32,
+    k: u32,
+    n: u32,
+    duration_ns: *i128,
+    error_code: *?anyerror,
+
+    fn run(task: *NPUTask) void {
+        const start = std.time.nanoTimestamp();
+        task.engine.matmul(task.a, task.b, task.c, task.m, task.k, task.n) catch |err| {
+            task.error_code.* = err;
+            return;
+        };
+        const end = std.time.nanoTimestamp();
+        task.duration_ns.* = end - start;
+        task.error_code.* = null;
+    }
+};
+
+pub fn main() !void {
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
