+    const queue = objc.deviceNewCommandQueue(device) orelse return error.CommandQueueFailed;
+
+    var gpu_engine = try metal_bf16.MetalBF16MatmulEngine.init(allocator, device, queue);
+    defer gpu_engine.deinit();
+
+    var npu_engine = try bnns_ane.BNNSANEMatmulEngine.init(allocator);
+    defer npu_engine.deinit();
+
+    std.debug.print("✅ Engines initialized\n\n", .{});
+
+    // Allocate test data
+    // GPU: Large matmul (main LLM workload)
+    const m_gpu: u32 = 1;
+    const k_gpu: u32 = 5120;
+    const n_gpu: u32 = 5120;
+
+    const a_gpu = try allocator.alloc(BF16, m_gpu * k_gpu);
+    defer allocator.free(a_gpu);
+    const b_gpu = try allocator.alloc(BF16, k_gpu * n_gpu);
+    defer allocator.free(b_gpu);
+    const c_gpu = try allocator.alloc(BF16, m_gpu * n_gpu);
+    defer allocator.free(c_gpu);
+
+    @memset(a_gpu, 0x3F80);
+    @memset(b_gpu, 0x3F80);
+
+    // NPU: Small matmul (auxiliary task)
+    const m_npu: u32 = 1;
