+    std.debug.print("═══════════════════════════════════════════════════════════\n", .{});
+    std.debug.print("Test 1: Sequential Baseline\n", .{});
+    std.debug.print("═══════════════════════════════════════════════════════════\n\n", .{});
+
+    std.debug.print("GPU matmul: [{}, {}] × [{}, {}]\n", .{ m_gpu, k_gpu, k_gpu, n_gpu });
+    const start_gpu = std.time.nanoTimestamp();
+    try gpu_engine.matmul(a_gpu, b_gpu, c_gpu, m_gpu, k_gpu, n_gpu);
+    const gpu_time_ns = std.time.nanoTimestamp() - start_gpu;
+    const gpu_time_ms = @as(f64, @floatFromInt(gpu_time_ns)) / 1_000_000.0;
+    std.debug.print("  GPU time: {d:.2}ms\n\n", .{gpu_time_ms});
